#include <string>

class Product {
public:
    std::string name;
    double price;
    Product(std::string n, double p) : name(n), price(p) {}
};

#include <string>
#include <optional>

std::string get_name(std::optional<std::string> opt_name) {
    if (opt_name.has_value()) {
        return opt_name.value();
    }
    return "Unknown";
}

